async function validatePlan(plan: Plan): Promise<boolean> {
  const steps = plan.Steps;
  const missingFunctions = steps.filter(step => 
    !kernel.functions.getFunction(step.Function?.PluginName, step.Function?.Name)
  );

  if (missingFunctions.length > 0) {
    console.error('🚨 INVALID PLAN:', missingFunctions.map(s => s.Function?.Name));
    return false;
  }
  return true;
}
