from semantic_kernel import kernel_function
def error_boundary_plugin(original_plugin):
    @kernel_function
    async def safe_plugin(context: KernelFunctionContext):
        try:
            return await original_plugin(context)
        except Exception as e:
            context.Variables.clear()  # Sanitize contaminated state
            context.Variables['error'] = str(e)
            context.Variables['success'] = 'false'
            return context
    return safe_plugin
