import { ActionPlanner } from '@semantic-kernel/planners-action';

const fallbackPlanner = new ActionPlanner(kernel);

async function executePlanWithFallback(plan: Plan): Promise<PlanExecutionResult> {
  try {
    return await kernel.planner.executePlanAsync(plan);
  } catch (error) {
    console.warn('Primary plan failed, trying fallback:', error);
    const fallbackPlan = await fallbackPlanner.createPlan('execute task safely');
    return await kernel.planner.executePlanAsync(fallbackPlan);
  }
}
